import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"; // useQuery : fetch data , useMutation : update data(PUT , POST , DELETE) , useQueryClient : control cache
import { employeeApi } from "@/api/employeeApi";
import type { CreateEmployeeRequest, UpdateEmployeeRequest } from "@/types";
import { enqueueSnackbar } from "notistack";

/*
  With TanStack you get :
  caching : Stores data by queryKey => queryKey: ["employees"]
  auto refetch
  loading state
  error handling
  background updates
 */
export function useEmployees() {
  return useQuery({
    queryKey: ["employees"], // Unique identifier for cache
    queryFn: employeeApi.getAll, // unction that fetches data
  }); // Result :  const { data, isLoading } = useEmployees();
}

export function useEmployee(id: number) {
  return useQuery({
    queryKey: ["employees", id], // Unique per employee
    queryFn: () => employeeApi.getById(id),
    enabled: !!id, // Prevents execution if id is falsy
  });
}

export function useEmployeeByUserId(userId?: number) {
  return useQuery({
    queryKey: ["employees", "by-user", userId],
    queryFn: () => employeeApi.getByUserId(userId!),
    enabled: !!userId,
  });
}

export function useCreateEmployee() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (data: CreateEmployeeRequest) => employeeApi.create(data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["employees"] });
      qc.invalidateQueries({ queryKey: ["positions"] });
      enqueueSnackbar("Employee created successfully", { variant: "success" });
    },
    onError: () =>
      enqueueSnackbar("Failed to create employee", { variant: "error" }),
  });
}

export function useUpdateEmployee() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, data }: { id: number; data: UpdateEmployeeRequest }) =>
      employeeApi.update(id, data),
    onSuccess: (response) => {
      qc.invalidateQueries({ queryKey: ["employees"] });
      qc.invalidateQueries({ queryKey: ["positions"] });
      qc.invalidateQueries({ queryKey: ["departments"] });
      enqueueSnackbar(response.message || "Employee updated successfully", { variant: "success" });
    },
    onError: () =>
      enqueueSnackbar("Failed to update employee", { variant: "error" }),
  });
}

export function useDeleteEmployee() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: number) => employeeApi.delete(id),
    onSuccess: (response) => {
      qc.invalidateQueries({ queryKey: ["employees"] });
      qc.invalidateQueries({ queryKey: ["positions"] });
      qc.invalidateQueries({ queryKey: ["departments"] });
      enqueueSnackbar(response.message || "Employee deleted successfully", { variant: "success" });
    },
    onError: () =>
      enqueueSnackbar("Failed to delete employee", { variant: "error" }),
  });
}
import { authApi } from "@/api/authApi";

export function useResetCredentials() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ userId, data }: { userId: number; data: { username: string; newPassword: string } }) =>
      authApi.resetCredentials(userId, data),
    onSuccess: (response) => {
      qc.invalidateQueries({ queryKey: ["employees"] });
      enqueueSnackbar(response.message || "Credentials reset successfully", { variant: "success" });
    },
    onError: (error: any) => {
      const msg = error.response?.data?.message || "Failed to reset credentials";
      enqueueSnackbar(msg, { variant: "error" });
    },
  });
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import {
  Box,
  Typography,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  CircularProgress,
  Alert,
  Stack,
  Card,
  CardContent,
  MenuItem,
  Select,
  FormControl,
  InputLabel,
  TablePagination,
  Grid,
} from "@mui/material";
import { attendanceApi } from "@/api/attendanceApi";
import type { MyAttendanceRecord } from "@/types";

export default function MyAttendance() {
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);

  // Filter states
  const [year, setYear] = useState<number | "">("");
  const [month, setMonth] = useState<number | "">("");
  const [day, setDay] = useState<number | "">("");

  const { data: result, isLoading, error } = useQuery({
    queryKey: ["myAttendance", year, month, day],
    queryFn: () => attendanceApi.getMyAttendance(
      year === "" ? undefined : year,
      month === "" ? undefined : month,
      day === "" ? undefined : day
    ),
  });

  const handleChangePage = (event: unknown, newPage: number) => {
    setPage(newPage);
  };

  const handleChangeRowsPerPage = (event: React.ChangeEvent<HTMLInputElement>) => {
    setRowsPerPage(parseInt(event.target.value, 10));
    setPage(0);
  };

  const handleYearChange = (e: any) => {
    setYear(e.target.value);
    setPage(0);
  };

  const handleMonthChange = (e: any) => {
    setMonth(e.target.value);
    setPage(0);
  };

  const handleDayChange = (e: any) => {
    setDay(e.target.value);
    setPage(0);
  };

  // Helper arrays for filters
  const years = Array.from({ length: 5 }, (_, i) => new Date().getFullYear() - i);
  const months = Array.from({ length: 12 }, (_, i) => i + 1);
  const days = Array.from({ length: 31 }, (_, i) => i + 1);

  if (isLoading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="50vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Alert severity="error" sx={{ mt: 3, borderRadius: 2 }}>
        Cannot load attendance data.
      </Alert>
    );
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "Present": return "success";
      case "Late": return "error";
      case "EarlyLeave": return "warning";
      case "Absent": return "default";
      default: return "default";
    }
  };

  const records = result?.records || [];

  return (
    <Box>
      <Typography variant="h4" fontWeight="bold" gutterBottom>
        My Attendance
      </Typography>

      <Box sx={{ mt: 3, mb: 2 }}>
        <Grid container spacing={2} alignItems="center">
          <Grid size={{ xs: 12, sm: 4, md: 2 }}>
            <FormControl fullWidth size="small">
              <InputLabel id="year-label">Year</InputLabel>
              <Select
                labelId="year-label"
                value={year}
                label="Year"
                onChange={handleYearChange}
                sx={{ bgcolor: "background.paper", borderRadius: 2 }}
              >
                <MenuItem value="">All Years</MenuItem>
                {years.map(y => (
                  <MenuItem key={y} value={y}>{y}</MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
          <Grid size={{ xs: 12, sm: 4, md: 2 }}>
            <FormControl fullWidth size="small">
              <InputLabel id="month-label">Month</InputLabel>
              <Select
                labelId="month-label"
                value={month}
                label="Month"
                onChange={handleMonthChange}
                sx={{ bgcolor: "background.paper", borderRadius: 2 }}
              >
                <MenuItem value="">All Months</MenuItem>
                {months.map(m => (
                  <MenuItem key={m} value={m}>
                    {new Date(2000, m - 1).toLocaleString('default', { month: 'long' })}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
          <Grid size={{ xs: 12, sm: 4, md: 2 }}>
            <FormControl fullWidth size="small">
              <InputLabel id="day-label">Day</InputLabel>
              <Select
                labelId="day-label"
                value={day}
                label="Day"
                onChange={handleDayChange}
                sx={{ bgcolor: "background.paper", borderRadius: 2 }}
              >
                <MenuItem value="">All Days</MenuItem>
                {days.map(d => (
                  <MenuItem key={d} value={d}>{d}</MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>
        </Grid>
      </Box>

      <Stack direction={{ xs: "column", sm: "row" }} spacing={3} mb={4} mt={2}>
        <Card sx={{ flex: 1, borderRadius: 2 }}>
          <CardContent sx={{ textAlign: "center" }}>
            <Typography variant="h6" color="text.secondary">Total Working Hours</Typography>
            <Typography variant="h4" fontWeight="bold" color="primary.main">
              {Math.floor((result?.totalWorkingMinutes || 0) / 60)}h {(result?.totalWorkingMinutes || 0) % 60}m
            </Typography>
          </CardContent>
        </Card>
        <Card sx={{ flex: 1, borderRadius: 2 }}>
          <CardContent sx={{ textAlign: "center" }}>
            <Typography variant="h6" color="text.secondary">Total Late</Typography>
            <Typography variant="h4" fontWeight="bold" color="error.main">
              {result?.totalLateMinutes || 0} mins
            </Typography>
          </CardContent>
        </Card>
        <Card sx={{ flex: 1, borderRadius: 2 }}>
          <CardContent sx={{ textAlign: "center" }}>
            <Typography variant="h6" color="text.secondary">Total Early Leave</Typography>
            <Typography variant="h4" fontWeight="bold" color="warning.main">
              {result?.totalEarlyLeaveMinutes || 0} mins
            </Typography>
          </CardContent>
        </Card>
      </Stack>

      <Paper sx={{ borderRadius: 2, overflow: "hidden" }}>
        <TableContainer>
          <Table>
            <TableHead sx={{ bgcolor: "background.default" }}>
              <TableRow>
                <TableCell><strong>Date</strong></TableCell>
                <TableCell><strong>Check In</strong></TableCell>
                <TableCell><strong>Check Out</strong></TableCell>
                <TableCell><strong>Status</strong></TableCell>
                <TableCell><strong>Late</strong></TableCell>
                <TableCell><strong>Early Leave</strong></TableCell>
                <TableCell><strong>Working Hours</strong></TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {records.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={7} align="center" sx={{ py: 3 }}>
                    <Typography color="text.secondary">No attendance records found.</Typography>
                  </TableCell>
                </TableRow>
              ) : (
                records
                  .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
                  .map((row: MyAttendanceRecord, index: number) => (
                  <TableRow key={index}>
                    <TableCell>{row.date}</TableCell>
                    <TableCell>{row.checkIn || "?"}</TableCell>
                    <TableCell>{row.checkOut || "?"}</TableCell>
                    <TableCell>
                      <Chip
                        label={row.status}
                        size="small"
                        color={getStatusColor(row.status) as any}
                        sx={{ 
                           fontWeight: 600,
                           ...(row.status === "Absent" && { bgcolor: "#e0e0e0", color: "#000" })
                        }}
                      />
                    </TableCell>
                    <TableCell>
                      <Typography color={row.lateMinutes > 0 ? "error.main" : "text.secondary"}>
                        {row.lateMinutes > 0 ? `${row.lateMinutes}m` : "?"}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography color={row.earlyLeaveMinutes > 0 ? "warning.main" : "text.secondary"}>
                        {row.earlyLeaveMinutes > 0 ? `${row.earlyLeaveMinutes}m` : "?"}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography color={row.workingMinutes > 0 ? "primary.main" : "text.secondary"} fontWeight={500}>
                        {row.workingMinutes > 0 ? `${Math.floor(row.workingMinutes / 60)}h ${row.workingMinutes % 60}m` : "?"}
                      </Typography>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </TableContainer>
        <TablePagination
          rowsPerPageOptions={[5, 10, 25, 50]}
          component="div"
          count={records.length}
          rowsPerPage={rowsPerPage}
          page={page}
          onPageChange={handleChangePage}
          onRowsPerPageChange={handleChangeRowsPerPage}
        />
      </Paper>
    </Box>
  );
}

import { useNavigate } from "react-router-dom";
import { useForm, FormProvider } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useCreateDepartment, useDepartments } from "@/hooks/useDepartments";
import { useEmployees } from "@/hooks/useEmployees";
import { FormInput } from "@/components/shared/FormInput";
import { FormSelect } from "@/components/shared/FormSelect";
import { handleApiErrors } from "@/utils/handleApiErrors";
import { useSnackbar } from "notistack";
import {
  Box,
  Typography,
  Button,
  Card,
  CardContent,
  CardHeader,
  IconButton,
  CircularProgress,
  Divider,
  Grid,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";

const schema = z.object({
  departmentName: z.string().min(1, "Department name is required"),
  description: z.string().optional(),
});

type FormData = z.infer<typeof schema>;

export default function CreateDepartment() {
  const navigate = useNavigate();
  const createMutation = useCreateDepartment();
  const { data: employees } = useEmployees();
  const { data: departments } = useDepartments();
  const { enqueueSnackbar } = useSnackbar();

  const methods = useForm<FormData>({
    resolver: zodResolver(schema) as any,
    defaultValues: {
      departmentName: "",
      description: "",
    },
});

  const onSubmit = (values: FormData) => {
    createMutation.mutate(
      {
        departmentName: values.departmentName,
        description: values.description,
      },
      {
        onSuccess: () => {
          navigate("/departments");
        },
        onError: (error) => {
          const message = handleApiErrors(error, methods);
          enqueueSnackbar(message, { variant: "error" });
        },
      },
    );
  };

  return (
    <Box sx={{ display: "flex", flexDirection: "column", gap: 3 }}>
      <Box sx={{ display: "flex", alignItems: "center", gap: 2 }}>
        <IconButton onClick={() => navigate("/departments")}>
          <ArrowBackIcon />
        </IconButton>
        <Box>
          <Typography variant="h1">Create Department</Typography>
          <Typography variant="body2" color="text.secondary">
            Add a new department
          </Typography>
        </Box>
      </Box>
      <Card>
        <CardHeader
          title="Department Details"
          titleTypographyProps={{ variant: "h2" }}
        />
        <Divider />
        <CardContent>
          <FormProvider {...methods}>
            <Box
              component="form"
              onSubmit={methods.handleSubmit(onSubmit)}
              sx={{ display: "flex", flexDirection: "column", gap: 2 }}
            >
              <Grid container spacing={2}>
                <Grid size={{ xs: 12, sm: 6 }}>
                  <FormInput
                    name="departmentName"
                    label="Department Name"
                    placeholder="Engineering"
                  />
                </Grid>
                <Grid size={{ xs: 12 }}>
                  <FormInput
                    name="description"
                    label="Description"
                    placeholder="Department description..."
                  />
                </Grid>
              </Grid>
              <Box sx={{ display: "flex", gap: 1.5, pt: 2 }}>
                <Button
                  type="submit"
                  variant="contained"
                  disabled={createMutation.isPending}
                  sx={{
                    background: "linear-gradient(135deg, #3b82f6, #1d4ed8)",
                    "&:hover": {
                      background: "linear-gradient(135deg, #2563eb, #1e40af)",
                    },
                  }}
                >
                  {createMutation.isPending && (
                    <CircularProgress
                      size={18}
                      sx={{ mr: 1, color: "inherit" }}
                    />
                  )}
                  Create Department
                </Button>
                <Button
                  variant="outlined"
                  onClick={() => navigate("/departments")}
                >
                  Cancel
                </Button>
              </Box>
            </Box>
          </FormProvider>
        </CardContent>
      </Card>
    </Box>
  );
}

import { useState, useMemo, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useDepartments, useDeleteDepartment } from "@/hooks/useDepartments";
import { useEmployees } from "@/hooks/useEmployees";
import { usePositions } from "@/hooks/usePositions";
import { DataTable, type Column } from "@/components/shared/DataTable";
import { SearchInput } from "@/components/shared/SearchInput";
import { ConfirmDialog } from "@/components/shared/ConfirmDialog";
import { Box, Typography, Button, Chip } from "@mui/material";
import AddIcon from "@mui/icons-material/Add";
import { ActionButtons } from "@/components/shared/ActionButtons";
import type { Department } from "@/types";
import { getGeneralErrors } from "@/utils/handleApiErrors";
import { useSnackbar } from "notistack";
import { AxiosError } from "axios";
import { ApiResponse } from "@/types";

export default function DepartmentList() {
  const navigate = useNavigate();
  const { data, isLoading: departmentsLoading } = useDepartments();
  const { data: employees, isLoading: employeesLoading } = useEmployees();
  const { data: positions, isLoading: positionsLoading } = usePositions();
  const isLoading = departmentsLoading || employeesLoading || positionsLoading;
  const deleteMutation = useDeleteDepartment();
  const { enqueueSnackbar } = useSnackbar();
  const [deleteTarget, setDeleteTarget] = useState<number | null>(null);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);

  const filteredData = useMemo(() => {
    if (!data) return [];
    if (!search) return data;
    const s = search.toLowerCase();
    return data.filter((d) => d.departmentName?.toLowerCase().includes(s));
  }, [data, search]);

  // Reset page when search changes
  useEffect(() => {
    setPage(0);
  }, [search]);

  const pagedData = filteredData.slice(page * rowsPerPage, (page + 1) * rowsPerPage);

  const handleDelete = () => {
    if (deleteTarget !== null) {
      deleteMutation.mutate(deleteTarget, {
        onSuccess: () => {
          setDeleteTarget(null);
        },
        onError: (error) => {
          const errors = getGeneralErrors(error);
          if (errors.length > 0) {
            errors.forEach((msg) => enqueueSnackbar(msg, { variant: "error" }));
          } else {
            const data = (error as AxiosError<ApiResponse<any>>)?.response?.data;
            enqueueSnackbar(data?.message || "Failed to delete department", { variant: "error" });
          }
        },
      });
    }
  };

  const columns: Column<Department>[] = [
    {
      header: "Department Name",
      cell: (row) => (
        <Typography variant="body2" fontWeight={500}>
          {row.departmentName}
        </Typography>
      ),
    },
    {
      header: "Description",
      cell: (row) => (
        <Typography variant="body2" color="text.secondary" noWrap sx={{ maxWidth: 200 }}>
          {row.description || "?"}
        </Typography>
      ),
    },
    {
      header: "Manager",
      cell: (row) => {
        const m = employees?.find((e) => e.id === row.managerId);
        return m ? `${m.firstName} ${m.lastname}` : "None";
      },
    },
    {
      header: "Employees",
      cell: (row) => {
        const deptPositionIds = positions
          ?.filter((p) => p.departmentId === row.id)
          .map((p) => p.id);
        const count = employees?.filter((e) =>
          deptPositionIds?.includes(e.positionId)
        ).length;
        return (
          <Chip
            label={count || 0}
            size="small"
            sx={{ fontWeight: "bold", bgcolor: "rgba(59, 130, 246, 0.1)", color: "#2563eb" }}
          />
        );
      },
    },
    {
      header: "Status",
      cell: (row) => (
        <Chip
          label={row.isActive !== false ? "Active" : "Inactive"}
          size="small"
          color={row.isActive !== false ? "success" : "default"}
          variant="outlined"
          sx={{ fontWeight: 500 }}
        />
      ),
    },
    {
      header: "Actions",
      cell: (row) => (
        <ActionButtons
          basePath="/departments"
          id={row.id}
          canEdit={true}
          canDelete={true}
          onDelete={(id) => setDeleteTarget(Number(id))}
        />
      ),
    },
  ];

  return (
    <Box sx={{ display: "flex", flexDirection: "column", gap: 3 }}>
      <Box
        sx={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <Box>
          <Typography variant="h1">Departments</Typography>
          <Typography variant="body2" color="text.secondary">
            Manage company departments
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => navigate("/departments/create")}
          sx={{
            background: "linear-gradient(135deg, #3b82f6, #1d4ed8)",
            "&:hover": {
              background: "linear-gradient(135deg, #2563eb, #1e40af)",
            },
          }}
        >
          Add Department
        </Button>
      </Box>

      <Box sx={{ maxWidth: 360 }}>
        <SearchInput
          value={search}
          onChange={setSearch}
          placeholder="Search departments..."
        />
      </Box>

      <DataTable 
        columns={columns} 
        data={pagedData} 
        loading={isLoading} 
        page={page}
        totalCount={filteredData.length}
        rowsPerPage={rowsPerPage}
        onPageChange={setPage}
        onRowsPerPageChange={(rows) => {
          setRowsPerPage(rows);
          setPage(0);
        }}
        onRowClick={(row) => navigate(`/departments/${row.id}`)}
      />

      <ConfirmDialog
        open={deleteTarget !== null}
        onOpenChange={(open) => !open && setDeleteTarget(null)}
        title="Delete Department"
        description="Are you sure? This will also delete all positions and employees assigned to this department. This action cannot be undone."
        onConfirm={handleDelete}
        loading={deleteMutation.isPending}
      />
    </Box>
  );
}

import { useNavigate, useParams } from "react-router-dom";
import { useForm, FormProvider } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import {
  useDepartment,
  useUpdateDepartment,
  useDepartments,
} from "@/hooks/useDepartments";
import { useEmployees } from "@/hooks/useEmployees";
import { usePositions } from "@/hooks/usePositions";
import { FormInput } from "@/components/shared/FormInput";
import { FormSelect } from "@/components/shared/FormSelect";
import { LoadingSpinner } from "@/components/shared/LoadingSpinner";
import { handleApiErrors } from "@/utils/handleApiErrors";
import { useSnackbar } from "notistack";
import {
  Box,
  Typography,
  Button,
  Card,
  CardContent,
  CardHeader,
  IconButton,
  CircularProgress,
  Divider,
  Grid,
} from "@mui/material";
import ArrowBackIcon from "@mui/icons-material/ArrowBack";
import { useEffect } from "react";

const schema = z.object({
  departmentName: z.string().min(1, "Department name is required"),
  description: z.string().optional(),
  managerId: z.coerce.number().optional(),
  isActive: z.string(),
});

type FormData = z.infer<typeof schema>;

export default function EditDepartment() {
  const { id } = useParams<{ id: string }>();
  const numId = Number(id);
  const navigate = useNavigate();
  const { data: department, isLoading } = useDepartment(numId);
  const { data: employees } = useEmployees();
  const { data: departments } = useDepartments();
  const { data: positions } = usePositions();
  const updateMutation = useUpdateDepartment();
  const { enqueueSnackbar } = useSnackbar();

  const methods = useForm<FormData>({
    resolver: zodResolver(schema) as any,
    defaultValues: {
      departmentName: "",
      description: "",
      managerId: undefined,
      isActive: "true",
    },
  });

  useEffect(() => {
    if (department) {
      methods.reset({
        departmentName: department.departmentName ?? "",
        description: department.description ?? "",
        managerId: department.managerId ?? undefined,
        isActive: department.isActive !== false ? "true" : "false",
      });
    }
  }, [department, methods]);

  const onSubmit = (values: FormData) => {
    updateMutation.mutate(
      {
        id: numId,
        data: {
          departmentName: values.departmentName,
          description: values.description,
          managerId: values.managerId || null,
          isActive: values.isActive === "true",
        },
      },
      {
        onSuccess: () => {
          navigate("/departments");
        },
        onError: (error) => {
          const message = handleApiErrors(error, methods);
          enqueueSnackbar(message, { variant: "error" });
        },
      },
    );
  };

  if (isLoading) return <LoadingSpinner />;

  return (
    <Box sx={{ display: "flex", flexDirection: "column", gap: 3 }}>
